inputs.script:
const cleanArg=(v)=>{const t=String(v==null?'':v).trim();return /^\{[a-zA-Z0-9_]+\}$/.test(t)?'':t;};
const norm=(s)=>(s||'').replace(/ /g,' ').replace(/\s+/g,' ').trim();
const rawLines=(el)=>(el?(el.innerText||el.textContent||''):'').split('\n').map((l)=>l.replace(/ /g,' ').replace(/\s+/g,' ').trim()).filter(Boolean);
const max=Math.max(1,Math.min(50,parseInt(cleanArg(arg0)||'20',10)||20));
const vertical=(cleanArg(arg1)||'people').toLowerCase();
const stripQ=(u)=>{try{const x=new URL(u,location.origin);let p=x.pathname;if(p.length>1&&p.endsWith('/'))p=p.slice(0,-1);return x.origin+p;}catch(e){return u||'';}};
const isDeg=(l)=>/^•?\s*(1st|2nd|3rd\+?)\b/i.test(l)||/^•\s/.test(l);
const isAct=(l)=>/^(Connect|Follow|Message|Pending|Save|Saved|Following|Remove connection|Unfollow)$/i.test(l);
const out=[];const seen=new Set();
if(vertical==='companies'){
  const links=[...document.querySelectorAll('main a[href*="/company/"]')];
  for(const a of links){const href=a.getAttribute('href')||'';if(href.indexOf('/company/')===-1)continue;if(a.children.length===1&&a.children[0].tagName==='IMG')continue;const ls=rawLines(a);if(!ls.length)continue;const key=stripQ(href);if(seen.has(key))continue;const name=ls[0];if(!name)continue;seen.add(key);let industry='';for(let i=1;i<ls.length;i++){const l=ls[i];if(l===name||isAct(l)||isDeg(l))continue;industry=l;break;}out.push({name:name,industry:industry,company_url:key});if(out.length>=max)break;}
}else if(vertical==='content'){
  const btns=[...document.querySelectorAll('button[aria-label^="Open control menu for post by "]')];
  for(const btn of btns){const author=norm((btn.getAttribute('aria-label')||'').replace('Open control menu for post by ',''));let card=btn.parentElement;let hops=0;while(card&&hops<15&&!card.querySelector('[data-testid="expandable-text-box"]')){card=card.parentElement;hops++;}const textEl=card?card.querySelector('[data-testid="expandable-text-box"]'):null;const text=textEl?norm(textEl.innerText||textEl.textContent||''):'';if(!text)continue;const key=author+'|'+text.slice(0,60);if(seen.has(key))continue;seen.add(key);out.push({author:author,text:text,post_url:''});if(out.length>=max)break;}
}else{
  const links=[...document.querySelectorAll('main a[href*="/in/"]')];
  for(const a of links){const href=a.getAttribute('href')||'';if(href.indexOf('/in/')===-1)continue;if(a.children.length===1&&a.children[0].tagName==='IMG')continue;const ls=rawLines(a);if(ls.length<1)continue;const key=stripQ(href);if(seen.has(key))continue;let name=ls[0].replace(/\s*•.*$/,'').trim();if(!name||/^view\b/i.test(name))continue;seen.add(key);let location='';for(let i=1;i<ls.length;i++){const l=ls[i];if(/^Current:/i.test(l))continue;if(l.indexOf(',')>=0&&l.length<80&&!isDeg(l)&&!isAct(l)){location=l;break;}}let headline='';const cur=ls.find((l)=>/^Current:/i.test(l));if(cur){headline=cur.replace(/^Current:\s*/i,'').trim();}else{for(let i=1;i<ls.length;i++){const l=ls[i];if(l===name||isDeg(l)||isAct(l)||l===location)continue;headline=l;break;}}out.push({name:name,headline:headline,location:location,profile_url:key});if(out.length>=max)break;}
}
return out;
